sql:
SELECT design_name
FROM ic_designs
WHERE status = 'approved';

SELECT design_id, status
FROM ic_designs
WHERE design_id = (SELECT MAX(design_id) FROM ic_designs);

SELECT status, COUNT(*) AS design_count
FROM ic_designs
GROUP BY status;

SELECT package_type
FROM ic_pictures
WHERE pin_count > 10;

SELECT COUNT(DISTINCT design_id) AS approved_design_count
FROM ic_designs
WHERE status = 'approved';

SELECT SUM(pin_count) AS total_wl_csp_pins
FROM ic_pictures
WHERE package_type = 'WLCSP';

SELECT design_name, description, updated_at, status
FROM ic_designs
ORDER BY updated_at DESC;

SELECT COUNT(pin_id) AS pin_count
FROM design_pins
WHERE design_id = 0;

external_knowledge:
; The 'designs' refer to IC (Integrated Circuit) designs; 
; The 'revisions' are changes made to these designs; 
; 'Access logs' represent records of when these designs were accessed; 
; 'Pins' refer to the physical connection points on the IC package.
